&WizardStep = new() &WizardStep.Code = !'TransmitirNFCe' &WizardStep.Title = 'Transmitir' &WizardStep.Description = 'Transmitir' &WizardSteps.Add(&WizardStep)
If &CurrentStep.IsEmpty() &CurrentStepAux = !'CapaNFCe' &WebSession.Remove(&Pgmname + !'_Data') Else &CurrentStepAux = &CurrentStep EndIf Do 'LoadWizardStepWC' StepTitles.Object = WizardStepsUnderlineWC.Create(&WizardSteps, &CurrentStepAux)
