GeraPdfDanfe.Call(&WizardData.CapaNFCe.EmpCod, &WizardData.CapaNFCe.FilCod, &WizardData.CapaNFCe.NfeCod, &UrlPDF, &UrlFisico)
RCOOpenWindow1.LinkOpen = Link(&UrlPDF) RCOOpenWindow1.OpenWindow(True, 500, 500, True, 0, 0, False)
