Sub 'LoadWizardStepWC'
If 1 = 2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case &CurrentStepAux = !'CapaNFCe' WizardStepWC.Object = wpEmiteNFCeCapaNFCe.Create(&Pgmname + !'_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'ProdutosNFCe' WizardStepWC.Object = wpEmiteNFCeProdutosNFCe.Create(&Pgmname + !'_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'TotaisNFCe' WizardStepWC.Object = wpEmiteNFCeTotaisNFCe.Create(&Pgmname + !'_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'TransmitirNFCe' WizardStepWC.Object = wpEmiteNFCeTransmitirNFCe.Create(&Pgmname + !'_Data', &PreviousStep, &GoingBack) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Else Do Case Case &CurrentStepAux = !'CapaNFCe' WizardStepWC.Object = wpEmiteNFCeCapaNFCe.Create('wpEmiteNFCe_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'ProdutosNFCe' WizardStepWC.Object = wpEmiteNFCeProdutosNFCe.Create('wpEmiteNFCe_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'TotaisNFCe' WizardStepWC.Object = wpEmiteNFCeTotaisNFCe.Create('wpEmiteNFCe_Data', &PreviousStep, &GoingBack) Case &CurrentStepAux = !'TransmitirNFCe' WizardStepWC.Object = wpEmiteNFCeTransmitirNFCe.Create('wpEmiteNFCe_Data', &PreviousStep, &GoingBack) EndCase EndIf
EndSub
